from __future__ import annotations
from dataclasses import dataclass, field
import math

@dataclass
class LATSNode:
    state: str              # task + trajectory so far (full context)
    action: str = ""        # the action that led here from parent
    parent: LATSNode | None = None
    children: list[LATSNode] = field(default_factory=list)
    visits: int = 0
    value: float = 0.0      # cumulative value / visits = average value
    is_terminal: bool = False
    reward: float = 0.0     # 1.0 = solved, 0.0 = failed
    reflection: str = ""    # written by LLM on failure

    def ucb1(self, exploration: float = 1.4) -> float:
        """Upper Confidence Bound 1 score for node selection."""
        if self.visits == 0:
            return float("inf")  # always expand unvisited nodes first
        parent_visits = self.parent.visits if self.parent else self.visits
        return (
            self.value / self.visits
            + exploration * math.sqrt(math.log(parent_visits) / self.visits)
        )

    def best_child(self) -> LATSNode:
        """Return child with highest UCB1 score."""
        return max(self.children, key=lambda c: c.ucb1())

    def is_fully_expanded(self, branching_factor: int) -> bool:
        return len(self.children) >= branching_factor

    def trajectory(self) -> list[str]:
        """Return the sequence of actions from root to this node."""
        path = []
        node: LATSNode | None = self
        while node and node.parent:
            path.insert(0, node.action)
            node = node.parent
        return path

