def collect_reflections(root: LATSNode) -> list[str]:
    """Gather all reflections from failed terminal nodes in the tree."""
    reflections = []
    stack = [root]
    while stack:
        node = stack.pop()
        if node.reflection:
            reflections.append(node.reflection)
        stack.extend(node.children)
    return reflections

def is_action_flagged(action: str, reflections: list[str],
                      similarity_threshold: float = 0.6) -> bool:
    """Check if an action resembles a previously reflected failure."""
    action_tokens = set(action.lower().split())
    for r in reflections:
        # Rough keyword match: if the action shares many words with reflection
        r_tokens = set(r.lower().split())
        if action_tokens and r_tokens:
            overlap = len(action_tokens & r_tokens) / len(action_tokens | r_tokens)
            if overlap > similarity_threshold:
                return True
    return False

def expand_with_pruning(
    node: LATSNode,
    k: int,
    tools: list[str],
    max_depth: int = 5,
) -> list[LATSNode]:
    depth = len(node.trajectory())
    if depth >= max_depth:
        node.is_terminal = True
        node.reward = 0.0
        return []

    children = expand(node, k=k + 2, tools=tools)  # generate extras for pruning
    reflections = collect_reflections(node)         # reflections in this subtree

    # Prune children that repeat known-failed action patterns
    children = [
        c for c in children
        if not is_action_flagged(c.action, reflections)
    ][:k]  # keep at most k after pruning

    return children

# Benchmarking: track LLM calls for cost estimation
class LATSCostTracker:
    def __init__(self):
        self.expansion_calls = 0
        self.value_calls = 0
        self.reflection_calls = 0

    @property
    def total_calls(self) -> int:
        return self.expansion_calls + self.value_calls + self.reflection_calls

    def estimate_cost_usd(self, input_tokens_per_call: int = 500) -> float:
        total_tokens = self.total_calls * input_tokens_per_call
        return total_tokens / 1_000_000 * 0.15  # gpt-4o-mini pricing approx
